114→  const args = process.argv.slice(2);
115→  const command = args[0];
116→
117→  if (command === '--help' || command === '-h') {
118→    showHelp();
119→    process.exit(0);
120→  }
121→
122→  if (command === '--version' || command === '-v') {
123→    console.log(`belt-setup v${getVersion()}`);
124→    process.exit(0);
125→  }
126→
127→  // Default behavior: run setup
128→  const targetDir =
129→    command && !command.startsWith('-') ? command : process.cwd();
