 83→export default defineConfig(() => {
 84→  const srcDir = resolve(__dirname, 'src');
 85→  const pkgPath = resolve(__dirname, 'package.json');
 86→  const entries = discoverEntries(srcDir);
 87→
 88→  updatePackageJson(entries, pkgPath);
 89→
 90→  console.log('Discovered entries:', Object.keys(entries));
 91→
 92→  const config: UserConfig = {
 93→    build: {
 94→      lib: {
 95→        entry: entries,
 96→        name: 'beltai',
 97→        formats: [
 98→          'es',
 99→          'cjs',
100→        ],
101→        fileName: (format, entryName) => {
102→          const ext = format === 'es' ? 'mjs' : 'cjs';
103→          return `${entryName}.${ext}`;
104→        },
105→      },
106→      sourcemap: true,
107→      minify: 'terser',
108→    },
109→    plugins: [
110→      externalizeDeps(),
111→      dts({
112→        rollupTypes: false,
113→        tsconfigPath: 'tsconfig.prod.json',
114→      }),
115→      {
116→        enforce: 'pre',
117→        ...nodeExternals(),
118→      },
119→      tsconfigPaths(),
120→    ],
121→  };
122→
123→  return config;
124→});
