127→export function setup(targetDir: string): void {
128→  const projectDir = resolve(targetDir);
129→  const claudeDir = join(projectDir, '.claude');
130→  const settingsPath = join(claudeDir, 'settings.json');
131→  const agentrcPath = join(projectDir, '.agentrc.ts');
132→
133→  console.log('\n🔧 belt-ai setup');
134→  console.log(`   Target: ${projectDir}\n`);
135→
136→  // Create .claude directory
137→  if (!existsSync(claudeDir)) {
138→    mkdirSync(claudeDir, { recursive: true });
139→    console.log('✅ Created .claude/');
140→  }
141→
142→  // Create or update settings.json
143→  let settings: ClaudeSettings = {
144→    $schema: 'https://json.schemastore.org/claude-code-settings.json',
145→    hooks: {},
146→  };
147→
148→  if (existsSync(settingsPath)) {
149→    try {
150→      const existing = JSON.parse(readFileSync(settingsPath, 'utf-8'));
151→      settings = {
152→        ...settings,
153→        ...existing,
154→      };
155→      console.log('📝 Merging existing .claude/settings.json');
156→    } catch {
157→      console.log('⚠️  Could not parse existing settings.json, creating new');
158→    }
159→  }
160→
161→  settings.hooks = mergeHooks(settings.hooks, REQUIRED_HOOKS);
162→  writeFileSync(settingsPath, JSON.stringify(settings, null, 2) + '\n');
163→  console.log('✅ Updated .claude/settings.json');
164→
165→  // Create .agentrc.ts if not exists
166→  if (!existsSync(agentrcPath)) {
167→    writeFileSync(agentrcPath, AGENTRC_TEMPLATE);
168→    console.log('✅ Created .agentrc.ts');
169→  } else {
170→    console.log('📝 .agentrc.ts already exists, skipping');
171→  }
172→
173→  console.log('\n✨ AgentRC setup complete!');
174→  console.log('\nNext steps:');
175→  console.log('  1. Edit .agentrc.ts to define your rules and hooks');
176→  console.log('  2. Start a Claude Code session in this project');
177→  console.log('  3. Rules will be automatically enforced\n');
178→}
