180→// CLI entry point - only run when executed directly (not when imported)
181→function isMainModule(): boolean {
182→  if (typeof process === 'undefined' || !process.argv) {
183→    return false;
184→  }
185→
186→  const scriptPath = process.argv[1];
187→  if (!scriptPath) return false;
188→
189→  // Check if this module is being run directly
190→  const modulePath = import.meta.url?.replace('file://', '') || '';
191→  const normalizedScript = scriptPath.replace(/\\/g, '/');
192→  const normalizedModule = modulePath.replace(/\\/g, '/');
193→
194→  return (
195→    normalizedScript === normalizedModule ||
196→    normalizedScript.endsWith('setup.mjs') ||
197→    normalizedScript.endsWith('setup.cjs') ||
198→    normalizedScript.endsWith('belt-ai') ||
199→    normalizedScript.endsWith('belt-ai-setup')
200→  );
201→}
202→
203→if (isMainModule()) {
204→  const args = process.argv.slice(2);
205→  const command = args[0];
206→  const targetDir = args[1] || process.cwd();
207→
208→  if (command === 'setup' || !command) {
209→    setup(targetDir);
210→  } else {
211→    console.log('Usage: belt-ai setup [directory]');
212→    process.exit(1);
213→  }
214→}
